def edit_distance(a, b):
    m, n = len(a), len(b)
    dp = [[0] * (n + 1) for _ in range(2)]

    for j in range(n + 1):
        dp[0][j] = j

    for i in range(1, m + 1):
        current = i % 2
        prev = (i - 1) % 2
        dp[current][0] = i
        for j in range(1, n + 1):
            if a[i - 1] == b[j - 1]:
                cost = 0
            else:
                cost = 1
            dp[current][j] = min(
                dp[prev][j] + 1,      # deletion
                dp[current][j - 1] + 1,  # insertion
                dp[prev][j - 1] + cost   # substitution
            )

    return dp[m % 2][n]
