def evaluate(expr: str) -> float:
    """
    Evaluates a string arithmetic expression containing non-negative integers/decimals,
    binary operators (+, -, *, /), unary +/-, and parentheses.

    Supports standard operator precedence (*, / before +, -), left-associativity,
    and ignores whitespace. Returns the result as a float.

    Raises:
        ValueError: If the expression is malformed (e.g., invalid syntax, mismatched parentheses).
    """
    if not isinstance(expr, str):
        raise ValueError("Input must be a string")

    tokens = []
    i = 0
    n = len(expr)

    while i < n:
        char = expr[i]

        if char.isspace():
            i += 1
            continue

        if char.isdigit() or char == '.':
            start = i
            has_dot = (char == '.')
            i += 1
            while i < n and (expr[i].isdigit() or expr[i] == '.'):
                if expr[i] == '.':
                    if has_dot:
                        raise ValueError("Invalid number format: multiple decimal points")
                    has_dot = True
                i += 1
            num_str = expr[start:i]
            try:
                tokens.append(float(num_str))
            except ValueError:
                raise ValueError(f"Invalid number: {num_str}")
            continue

        if char in '+-*/()':
            tokens.append(char)
            i += 1
            continue

        raise ValueError(f"Invalid character: {char}")

    if not tokens:
        raise ValueError("Empty expression")

    def parse_expression(pos):
        left, pos = parse_term(pos)

        while pos < len(tokens) and tokens[pos] in ('+', '-'):
            op = tokens[pos]
            right, pos = parse_term(pos + 1)
            if op == '+':
                left += right
            else:
                left -= right

        return left, pos

    def parse_term(pos):
        left, pos = parse_factor(pos)

        while pos < len(tokens) and tokens[pos] in ('*', '/'):
            op = tokens[pos]
            right, pos = parse_factor(pos + 1)
            if op == '*':
                left *= right
            else:
                if right == 0.0:
                    raise ValueError("Division by zero")
                left /= right

        return left, pos

    def parse_factor(pos):
        if pos >= len(tokens):
            raise ValueError("Unexpected end of expression")

        token = tokens[pos]

        if token == '(':
            val, pos = parse_expression(pos + 1)
            if pos >= len(tokens) or tokens[pos] != ')':
                raise ValueError("Missing closing parenthesis")
            return val, pos + 1

        if isinstance(token, float):
            return token, pos + 1

        if token in ('+', '-'):
            val, pos = parse_factor(pos + 1)
            return -val if token == '-' else val, pos

        raise ValueError(f"Unexpected token: {token}")

    result, final_pos = parse_expression(0)

    if final_pos != len(tokens):
        raise ValueError("Invalid expression structure")

    return float(result)
